import React from 'react';
import { ButtonDemo } from './ButtonDemo';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '28rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Button Accessibility</h1>
      <ButtonDemo />
    </div>
  );
}

import React, { useState } from 'react';
import './styles.css';

export const ButtonDemo: React.FC = () => {
  const [output, setOutput] = useState('Click a button');
  const [toggled, setToggled] = useState(false);

  return (
    <div className="demo">
      {/* TODO: Fix this to be accessible.
          Currently a <div> with just onClick — not keyboard-operable, no role, no focus */}
      <div
        data-testid="action-btn"
        className="fake-btn"
        onClick={() => setOutput('Action clicked!')}
      >
        Action
      </div>

      {/* TODO: Fix this toggle button.
          Needs to communicate toggled state with aria-pressed */}
      <div
        data-testid="toggle-btn"
        className={`fake-btn${toggled ? ' fake-btn--active' : ''}`}
        onClick={() => {
          setToggled(!toggled);
          setOutput(toggled ? 'Toggled OFF' : 'Toggled ON');
        }}
      >
        {toggled ? '● ON' : '○ OFF'}
      </div>

      {/* TODO: Fix this icon-only button.
          Has no accessible name — screen readers say nothing useful */}
      <span
        data-testid="icon-btn"
        className="fake-btn fake-btn--icon"
        onClick={() => setOutput('Settings opened!')}
      >
        ⚙
      </span>

      {/* TODO: Fix this delete button.
          Not keyboard-accessible */}
      <div
        data-testid="delete-btn"
        className="fake-btn fake-btn--danger"
        onClick={() => setOutput('Item deleted!')}
      >
        🗑 Delete
      </div>

      <p data-testid="output" className="demo__output">{output}</p>
    </div>
  );
};

.demo {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  align-items: center;
}

.fake-btn {
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  padding: 0.5rem 1rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: #f9fafb;
  cursor: pointer;
  font-size: 0.875rem;
  user-select: none;
}

.fake-btn:hover {
  background: #e5e7eb;
}

.fake-btn:focus-visible {
  outline: 2px solid #3b82f6;
  outline-offset: 2px;
}

.fake-btn--active {
  background: #dbeafe;
  border-color: #93c5fd;
  color: #1d4ed8;
}

.fake-btn--icon {
  padding: 0.5rem;
  font-size: 1.125rem;
}

.fake-btn--danger {
  border-color: #fca5a5;
  color: #dc2626;
}

.fake-btn--danger:hover {
  background: #fef2f2;
}

.demo__output {
  width: 100%;
  margin-top: 0.75rem;
  padding: 0.75rem;
  background: #f3f4f6;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  color: #374151;
}

