import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Accessible Button Roles', () => {
  it('action button is keyboard operable', () => {
    render(<App />);
    const btn = screen.getByTestId('action-btn');
    // Must be focusable
    expect(btn.tabIndex).toBeGreaterThanOrEqual(0);
    // Must respond to keyboard
    btn.focus();
    fireEvent.keyDown(btn, { key: 'Enter' });
    expect(screen.getByTestId('output')).toHaveTextContent('Action clicked!');
  });

  it('toggle button has aria-pressed', () => {
    render(<App />);
    const btn = screen.getByTestId('toggle-btn');
    expect(btn).toHaveAttribute('aria-pressed');
    fireEvent.click(btn);
    expect(btn.getAttribute('aria-pressed')).toBe('true');
    fireEvent.click(btn);
    expect(btn.getAttribute('aria-pressed')).toBe('false');
  });

  it('icon button has aria-label', () => {
    render(<App />);
    const btn = screen.getByTestId('icon-btn');
    expect(btn).toHaveAttribute('aria-label');
    expect(btn.getAttribute('aria-label')).toBeTruthy();
  });

  it('icon button is keyboard operable', () => {
    render(<App />);
    const btn = screen.getByTestId('icon-btn');
    expect(btn.tabIndex).toBeGreaterThanOrEqual(0);
    btn.focus();
    fireEvent.keyDown(btn, { key: ' ' });
    expect(screen.getByTestId('output')).toHaveTextContent('Settings opened!');
  });

  it('delete button is keyboard operable', () => {
    render(<App />);
    const btn = screen.getByTestId('delete-btn');
    expect(btn.tabIndex).toBeGreaterThanOrEqual(0);
    btn.focus();
    fireEvent.keyDown(btn, { key: 'Enter' });
    expect(screen.getByTestId('output')).toHaveTextContent('Item deleted!');
  });

  it('all buttons have button role', () => {
    render(<App />);
    const ids = ['action-btn', 'toggle-btn', 'icon-btn', 'delete-btn'];
    ids.forEach(id => {
      const el = screen.getByTestId(id);
      const tag = el.tagName.toLowerCase();
      const role = el.getAttribute('role');
      expect(tag === 'button' || role === 'button').toBe(true);
    });
  });
});

