import React, { useState } from 'react';
import './styles.css';

export const ButtonDemo: React.FC = () => {
  const [output, setOutput] = useState('Click a button');
  const [toggled, setToggled] = useState(false);

  return (
    <div className="demo">
      <button
        data-testid="action-btn"
        className="fake-btn"
        onClick={() => setOutput('Action clicked!')}
      >
        Action
      </button>

      <button
        data-testid="toggle-btn"
        className={`fake-btn${toggled ? ' fake-btn--active' : ''}`}
        aria-pressed={toggled}
        onClick={() => {
          setToggled(!toggled);
          setOutput(toggled ? 'Toggled OFF' : 'Toggled ON');
        }}
      >
        {toggled ? '● ON' : '○ OFF'}
      </button>

      <button
        data-testid="icon-btn"
        className="fake-btn fake-btn--icon"
        aria-label="Settings"
        onClick={() => setOutput('Settings opened!')}
      >
        ⚙
      </button>

      <button
        data-testid="delete-btn"
        className="fake-btn fake-btn--danger"
        onClick={() => setOutput('Item deleted!')}
      >
        🗑 Delete
      </button>

      <p data-testid="output" className="demo__output">{output}</p>
    </div>
  );
};
